/// The sync manager is unused by the stake query slice.
struct StubSyncManager;

impl RpcSyncManager for StubSyncManager {
    fn sync_height(&mut self) -> i64 {
        unimplemented!()
    }
}

fn state_from_name(name: &str) -> State {
    match name {
        "defined" => State::Defined,
        "started" => State::Started,
        "lockedin" => State::LockedIn,
        "active" => State::Active,
        "failed" => State::Failed,
        other => panic!("unknown threshold state {other}"),
    }
}

fn or_err<T>(field: &str, parse: impl Fn(&str) -> T) -> Result<T, String> {
    match field.strip_prefix("ERR:") {
        Some(err) => Err(err.to_string()),
        None => Ok(parse(field)),
    }
}

fn dispatch(
    server: &mut Server<MockChain3>,
    method_name: &str,
    cmd: &GoValue,
) -> Result<(GoValue, GoType), RPCError> {
    let (result, typ) = match method_name {
        "estimatestakediff" => (
            handlers::handle_estimate_stake_diff(server, cmd)?,
            results::estimate_stake_diff_result(),
        ),
        "existsliveticket" => (
            handlers::handle_exists_live_ticket(server, cmd)?,
            GoType::Bool,
        ),
        "existslivetickets" => (
            handlers::handle_exists_live_tickets(server, cmd)?,
            GoType::String,
        ),
        "getstakedifficulty" => (
            handlers::handle_get_stake_difficulty(server, cmd)?,
            results::get_stake_difficulty_result(),
        ),
        "getstakeversioninfo" => (
            handlers::handle_get_stake_version_info(server, cmd)?,
            results::get_stake_version_info_result(),
        ),
        "getstakeversions" => (
            handlers::handle_get_stake_versions(server, cmd)?,
            results::get_stake_versions_result(),
        ),
        "getvoteinfo" => (
            handlers::handle_get_vote_info(server, cmd)?,
            results::get_vote_info_result(),
        ),
        "getticketpoolvalue" => (
            handlers::handle_get_ticket_pool_value(server, cmd)?,
            GoType::Float64,
        ),
        "gettreasurybalance" => (
            handlers::handle_get_treasury_balance(server, cmd)?,
            results::get_treasury_balance_result(),
        ),
        "livetickets" => (
            handlers::handle_live_tickets(server, cmd)?,
            results::live_tickets_result(),
        ),
        other => panic!("unknown method {other}"),
    };
    Ok((result, typ))
}

#[test]
fn stake_query_handler_slice_matches_dcrd() {
    let params = mainnet_params();
    let mut registry = Registry::new();
    register_all(&mut registry);

    // The vote info agendas the dump's mock served.
    let agendas: Vec<ConsensusDeployment> = params
        .deployments
        .iter()
        .find(|(version, _)| *version == VOTE_INFO_VERSION)
        .map(|(_, agendas)| agendas.clone())
        .expect("mainnet deployments for the vote info version");

    // The header fixture shared with the chain-query slice.
    let header_fixture: BlockHeader = SLICE2_VECTORS
        .lines()
        .find_map(|line| {
            let f: Vec<&str> = line.split('|').collect();
            (f[0] == "blockfix").then(|| {
                let (block, _) = MsgBlock::from_bytes(&unhex(f[1])).unwrap();
                block.header
            })
        })
        .expect("block fixture");

    // The stake versions fixture list.
    let mut stake_versions: Vec<RpcStakeVersions> = Vec::new();
    for line in VECTORS.lines() {
        let f: Vec<&str> = line.split('|').collect();
        if f[0] != "sver" {
            continue;
        }
        let votes = f[5]
            .split(',')
            .map(|pair| {
                let (v, b) = pair.split_once(':').unwrap();
                (v.parse().unwrap(), b.parse().unwrap())
            })
            .collect();
        stake_versions.push(RpcStakeVersions {
            hash: f[1].parse().unwrap(),
            height: f[2].parse().unwrap(),
            block_version: f[3].parse().unwrap(),
            stake_version: f[4].parse().unwrap(),
            votes,
        });
    }
    assert_eq!(stake_versions.len(), 2, "stake versions fixture");

    let lines: Vec<&str> = VECTORS
        .lines()
        .filter(|l| l.starts_with("case|") || l.starts_with("mock3|") || l.starts_with("result|"))
        .collect();
    let mut cases = 0;
    let mut i = 0;
    while i < lines.len() {
        let case: Vec<&str> = lines[i].split('|').collect();
        let mock: Vec<&str> = lines[i + 1].split('|').collect();
        let result: Vec<&str> = lines[i + 2].split('|').collect();
        assert_eq!(case[0], "case");
        assert_eq!(mock[0], "mock3");
        assert_eq!(result[0], "result");
        i += 3;
        cases += 1;

        let name = case[2];
        let method_name = case[3];
        let params_json = utf8(case[4]);

        // Parse the command through the ported pipeline.
        let raw_params = split_json_array(&params_json);
        let param_refs: Vec<&str> = raw_params.iter().map(|s| s.as_str()).collect();
        let cmd_instance = parse_params(&registry, &method(method_name), &param_refs)
            .unwrap_or_else(|e| panic!("{name}: parse params: {e:?}"));
        let cmd = GoValue::Struct(cmd_instance.fields);

        // Decode the vote counts field: "choices;...,total,abstain" or
        // an ERR: prefix followed by the unused totals.
        let vc_parts: Vec<&str> = mock[11].splitn(3, ',').collect();
        let vote_counts = match vc_parts[0].strip_prefix("ERR:") {
            Some(err) => Err(err.to_string()),
            None => Ok(RpcVoteCounts {
                total: vc_parts[1].parse().unwrap(),
                total_abstain: vc_parts[2].parse().unwrap(),
                vote_choices: vc_parts[0].split(';').map(|c| c.parse().unwrap()).collect(),
            }),
        };

        let vote_info = match mock[12] {
            "OK" => Ok(agendas.clone()),
            "ERRUV" => Err(VoteInfoFailure {
                is_unknown_deployment_version: true,
                message: String::new(),
            }),
            other => Err(VoteInfoFailure {
                is_unknown_deployment_version: false,
                message: other.strip_prefix("ERR:").unwrap().to_string(),
            }),
        };

        let treasury = match mock[13] {
            "ERRUB" => Err(TreasuryBalanceFailure {
                is_unknown_block: true,
                is_no_treasury_balance: false,
                message: String::new(),
            }),
            "ERRNT" => Err(TreasuryBalanceFailure {
                is_unknown_block: false,
                is_no_treasury_balance: true,
                message: String::new(),
            }),
            other => match other.strip_prefix("ERR:") {
                Some(err) => Err(TreasuryBalanceFailure {
                    is_unknown_block: false,
                    is_no_treasury_balance: false,
                    message: err.to_string(),
                }),
                None => {
                    let ok = other.strip_prefix("OK:").unwrap();
                    let (height, balance) = ok.split_once(',').unwrap();
                    Ok(RpcTreasuryBalance {
                        block_height: height.parse().unwrap(),
                        balance: balance.parse().unwrap(),
                        updates: mock[14]
                            .split(',')
                            .filter(|u| !u.is_empty())
                            .map(|u| u.parse().unwrap())
                            .collect(),
                    })
                }
            },
        };

        // The header and threshold state share a row field; the cases
        // never script both to fail at once.
        let (header, state) = match mock[17].strip_prefix("ERR:") {
            Some(err) => (Err(err.to_string()), Err(err.to_string())),
            None => (Ok(header_fixture), Ok(state_from_name(mock[17]))),
        };

        let chain = MockChain3 {
            best: RpcBestState {
                hash: mock[2].parse().unwrap(),
                prev_hash: Hash([0u8; 32]),
                height: mock[3].parse().unwrap(),
                bits: 0,
                next_stake_diff: mock[4].parse().unwrap(),
                total_subsidy: 0,
                block_size: 0,
                num_txns: 0,
            },
            want_height: mock[5].parse().unwrap(),
            ticket_pool_value: or_err(mock[6], |v| v.parse().unwrap()),
            live: or_err(mock[7], |v| {
                v.split(',')
                    .filter(|h| !h.is_empty())
                    .map(|h| h.parse().unwrap())
                    .collect()
            }),
            check_live: mock[8] == "true",
            check_lives: mock[9]
                .split(',')
                .filter(|b| !b.is_empty())
                .map(|b| b == "true")
                .collect(),
            count_vote: or_err(mock[10], |v| v.parse().unwrap()),
            vote_counts,
            vote_info,
            treasury,
            stake_versions: match mock[15].strip_prefix("ERR:") {
                Some(err) => Err(err.to_string()),
                None => Ok(stake_versions.clone()),
            },
            block_hash_by_height: or_err(mock[16], |v| v.parse().unwrap()),
            header,
            state,
            estimate_err: name
                .contains("estimate err")
                .then(|| "estimate failed".to_string()),
        };
        let mut server = Server::new(Config {
            chain,
            chain_params: params.clone(),
            subsidy_cache: SubsidyCache::new(RpcSubsidyParams(params.clone())),
            min_relay_tx_fee: 10000,
            max_protocol_version: PROTOCOL_VERSION,
            sync_mgr: Box::new(StubSyncManager),
            conn_mgr: Box::new(()),
            tx_mempooler: Box::new(()),
            clock: Box::new(()),
            interfaces: Box::new(dcroxide_rpc::helpers::NoInterfaces),
            rand_u64: Box::new(|| 0),
            tx_indexer: None,
            db: Box::new(()),
            filterer_v2: Box::new(()),
            exists_addresser: None,
            log_manager: Box::new(()),
            fee_estimator: Box::new(()),
            block_templater: None,
            sanity_checker: Box::new(()),
            time_source: Box::new(()),
            proxy: String::new(),
            test_net: false,
            runtime_version: String::new(),
            cpu_miner: Box::new(()),
            mix_pooler: Box::new(()),
            profiler_mgr: Box::new(()),
            addr_manager: Box::new(()),
            mining_addrs: Vec::new(),
            user_agent_version: String::new(),
            net_info: Vec::new(),
            services: 0,
            request_shutdown: Box::new(|| {}),
            allow_unsynced_mining: false,
            rpc_user: String::new(),
            rpc_pass: String::new(),
            rpc_limit_user: String::new(),
            rpc_limit_pass: String::new(),
        });

        match dispatch(&mut server, method_name, &cmd) {
            Ok((value, typ)) => {
                assert_eq!(result[2], "ok", "{name}: expected an error");
                let got = gojson::encode(&typ, &value);
                assert_eq!(got, utf8(result[3]), "{name}: result");
            }
            Err(err) => {
                assert_eq!(result[2], "err", "{name}: unexpected error {err:?}");
                assert_eq!(
                    i64::from(err.code),
                    result[3].parse::<i64>().unwrap(),
                    "{name}: error code ({})",
                    err.message
                );
                assert_eq!(err.message, utf8(result[4]), "{name}: error message");
            }
        }
    }
    assert_eq!(cases, 41, "unexpected case count");
}
